-- Create "obs_notification_channels" table
CREATE TABLE "obs_notification_channels" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "name" character varying NOT NULL,
  "channel_type" character varying NOT NULL DEFAULT 'email',
  "status" character varying NOT NULL DEFAULT 'active',
  "min_severity" character varying NOT NULL DEFAULT 'warning',
  "config_json" jsonb NULL,
  "send_resolved" boolean NOT NULL DEFAULT true,
  PRIMARY KEY ("id")
);
-- Create index "obsnotificationchannel_status_channel_type" to table: "obs_notification_channels"
CREATE INDEX "obsnotificationchannel_status_channel_type" ON "obs_notification_channels" ("status", "channel_type");
-- Create index "obsnotificationchannel_name" to table: "obs_notification_channels"
CREATE UNIQUE INDEX "obsnotificationchannel_name" ON "obs_notification_channels" ("name");

-- Create "obs_notification_deliveries" table
CREATE TABLE "obs_notification_deliveries" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "channel_id" bigint NOT NULL,
  "alert_event_id" bigint NOT NULL,
  "alert_status" character varying NOT NULL DEFAULT 'firing',
  "severity" character varying NOT NULL DEFAULT 'warning',
  "status" character varying NOT NULL DEFAULT 'pending',
  "target" character varying NOT NULL,
  "attempt_count" bigint NOT NULL DEFAULT 0,
  "last_error" character varying NOT NULL DEFAULT '',
  "next_attempt_at" timestamptz NOT NULL,
  "delivered_at" timestamptz NULL,
  "last_attempt_at" timestamptz NULL,
  PRIMARY KEY ("id")
);
-- Create index "obsnotificationdelivery_status_next_attempt_at" to table: "obs_notification_deliveries"
CREATE INDEX "obsnotificationdelivery_status_next_attempt_at" ON "obs_notification_deliveries" ("status", "next_attempt_at");
-- Create index "obsnotificationdelivery_channel_id_created_at" to table: "obs_notification_deliveries"
CREATE INDEX "obsnotificationdelivery_channel_id_created_at" ON "obs_notification_deliveries" ("channel_id", "created_at");
-- Create index "obsnotificationdelivery_alert_event_id_created_at" to table: "obs_notification_deliveries"
CREATE INDEX "obsnotificationdelivery_alert_event_id_created_at" ON "obs_notification_deliveries" ("alert_event_id", "created_at");
-- Create index "obsnotificationdelivery_channel_id_alert_event_id_alert_status_target" to table: "obs_notification_deliveries"
CREATE UNIQUE INDEX "obsnotificationdelivery_channel_id_alert_event_id_alert_status_target" ON "obs_notification_deliveries" ("channel_id", "alert_event_id", "alert_status", "target");
